import { Request, RequestOptions } from '../../src/Request'
import { MAP_ERROR, StarlingError } from '../../src/error'

const NAMESPACE = 'starling_client-test-demo'
const URL_LOAD_TEXT =
  'https://starling.snssdk.com/check_and_get_text/b112ff70cd5411e99543214b5ec42534/normal/starling_client-test-demo?lang=en,zh&version=1'
const request = jest.fn()
let remote: Request
const options: RequestOptions = {
  request,
  timeout: 5000,
  apiKey: 'b112ff70cd5411e99543214b5ec42534',
  locale: 'en',
  zoneHost: 'https://starling.snssdk.com',
  fallbackLang: ['zh'],
  mode: 'normal',
  getReleaseVersion: () => '',
  cdn: ''
}

describe('单元测试 - request', () => {
  beforeEach(() => {
    jest.clearAllMocks()
    remote = new Request(options)
  })
  afterEach(() => {
    jest.clearAllMocks()
  })

  test('request - 请求成功', async () => {
    // given
    request.mockReturnValue({ data: { message: { text: 'text' }, status: 200 } })
    // when
    const text = await remote.getTexts([[NAMESPACE, '1']])
    // then
    expect(request).toBeCalledTimes(1)
    expect(request).toBeCalledWith(URL_LOAD_TEXT, { timeout: 5000 })
    expect(text).toEqual([{ text: 'text' }])
  })

  test('request - 失败 - 模拟网络错误', async () => {
    request.mockRejectedValue('error')
    try {
      await remote.getTexts([['namespace', '1']])
    } catch (error) {
      expect(error).toStrictEqual('error')
    }
  })

  test('request - 失败 - 模拟请求http状态码为1000', async () => {
    request.mockReturnValue({ data: { message: { text: 'text' }, status: 1000 } })
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.API_PARAMS_ERROR
    try {
      await remote.getTexts([['namespace', '1']])
    } catch (error) {
      expect(error).toStrictEqual(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
    }
  })

  test('request - 失败 - 模拟请求http状态码为1001', async () => {
    request.mockReturnValue({ data: { message: { text: 'text' }, status: 1001 } })
    const { ERROR_CODE, ERROR_MESSAGE } = MAP_ERROR.VERSION_NOT_FOUND
    try {
      await remote.getTexts([['namespace', '1']])
    } catch (error) {
      expect(error).toStrictEqual(new StarlingError(ERROR_CODE, ERROR_MESSAGE))
    }
  })

  test('request - 成功 - 发布版本和本地版本不为空，返回空对象骗取上层逻辑信任', async () => {
    remote = new Request({
      ...options,
      getReleaseVersion: () => '0.0.1'
    })
    const data = await remote.getTexts([[NAMESPACE, '1']])
    expect(data).toStrictEqual([{}])
  })

  test('request - 成功 - 无缓存', async () => {
    request.mockReturnValue({ data: { message: { text: 'text' }, status: 200 } })
    remote = new Request({
      ...options,
      getReleaseVersion: () => '0.0.1'
    })
    const text = await remote.getTexts([[NAMESPACE, '']])
    expect(text).toEqual([{ text: 'text' }])
  })

  test('request - 成功 - 后端无返回值', async () => {
    request.mockReturnValue({ data: { message: null, status: 200 } })
    remote = new Request({
      ...options
    })
    const text = await remote.getTexts([[NAMESPACE, '']])
    expect(text).toEqual([{}])
  })
})
